mapper.sql:
SELECT M1.ID, M1.TRUST_NO, M1.TRUST_TYPE, M1.CONTRACT_ID, M1.CUSTOMER_ID, M1.CUSTOMER_NAME, M1.PROCESS_CODE, M1.PROCESS_NAME, M1.CARGO_CATEGORY_CODE, M1.CARGO_CATEGORY_NAME, M1.TRADE_TYPE, M1.PLAN_QUANTITY, M1.PLAN_TON, M1.CARGO_OWNER_NAME, M1.CARGO_AGENT_NAME, M1.CARGO_NAME, M1. REMARK, M1.SHIPVOYAGE_ID, M1.SHIPVOYAGE_ITEM_ID, CONCAT(CONCAT(M1.SHIP_NAME,'_'),SHIPVOYAGE_ITEM_ID) AS SHIP_NAME , M1.SETTLEMENT_BASIS_CODE, M1.SETTLEMENT_BASIS_NAME, M1.CHECK_TON, M1.CHECK_NUMBER, M1.COMPANY_ID, M1.COMPANY_NAME, M1.STATUS, M2.NM AS STATUS_LABEL, M1.CREATE_BY, M1.CREATE_BY_NAME, M1.CREATE_TIME, M1.UPDATE_BY, M1.UPDATE_BY_NAME, M1.UPDATE_TIME, M1.RELEASE_BY, M1.RELEASE_BY_NAME, M1.RELEASE_TIME, M1.CHECK_BY, M1.CHECK_BY_NAME, M1.CHECK_TIME, M1.EXAMINE_BY, M1.EXAMINE_BY_NAME, M1.EXAMINE_TIME, M1.IMP_EXP, M1.IS_BILL, M1.IS_WEIQIAO_POUND_REMARK FROM T_BUS_TRUST M1 left join M_CONSTANTS M2 ON M1.STATUS=M2.CD and M2.TYPE_CD='BUS_TRUST_STATUS'
and M1.TRUST_NO like #{trustNo}
and M1.COMPANY_ID = #{companyId}
and M1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
and M1.SHIPVOYAGE_ID = #{shipvoyageId}
and CHARINDEX(#{customerId},M1.CUSTOMER_ID)
and M1.STATUS = #{status}

mapper.select:
select * from (WITH TBTC AS (SELECT TRUST_ID, CARGO_OWNER_NAME, CARGO_AGENT_NAME, CARGO_NAME, CARGO_INFO_ID, CONSIGNER_ID, BUSINESS_NO, CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO), TEMP AS (SELECT DISTINCT * FROM (SELECT DISTINCT TBT.ID, TBT.SHIPVOYAGE_ITEM_ID, CASE WHEN TBT.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR(TBT.SHIP_NAME) || '_' || TO_CHAR(TBT.VOYAGE) END "shipNameVoyage", TO_CHAR(TDS.SCN) "SCN" FROM T_BUS_TRUST TBT JOIN T_DIS_SHIPVOYAGE TDS ON TBT.SHIPVOYAGE_ID = TDS.ID WHERE TBT.TYPE IN ('卸船', '装船', '杂项') UNION SELECT DISTINCT TBT.ID, TBT2.SHIPVOYAGE_ITEM_ID, CASE WHEN TBT2.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR(TBT2.SHIP_NAME) || '_' || TO_CHAR(TBT2.VOYAGE) END "shipNameVoyage", TO_CHAR(TDS.SCN) "SCN" FROM T_BUS_TRUST TBT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_TRUST_CARGO TBTC2 ON TBTC.CARGO_INFO_ID = TBTC2.CARGO_INFO_ID JOIN T_BUS_TRUST TBT2 ON (TBT2.TYPE IN ('卸船', '装船', '杂项') AND TBTC2.TRUST_ID = TBT2.ID) JOIN T_DIS_SHIPVOYAGE TDS ON TBT2.SHIPVOYAGE_ID = TDS.ID where TBT.TRUST_TYPE in(2,3) UNION SELECT TBT.ID, TBCI.SHIPVOYAGE_ITEM_ID, CASE WHEN TBCI.SHIPVOYAGE_ID IS NOT NULL THEN TO_CHAR(TBCI.SHIP_NAME) || '_' || TO_CHAR(TBCI.VOYAGE) END "shipNameVoyage", TO_CHAR(TDS.SCN) "SCN" FROM T_BUS_TRUST TBT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID JOIN T_DIS_SHIPVOYAGE TDS ON TBCI.SHIPVOYAGE_ID = TDS.ID where TBT.TRUST_TYPE = 2 ) TEMP)
SELECT TBT.ID, TBT.TRUST_NO, TBT.TRUST_TYPE, TBT.CONTRACT_ID, TBT.CUSTOMER_ID, TBT.CUSTOMER_NAME, TBT.PROCESS_CODE, TBT.PROCESS_NAME, TBT.CARGO_CATEGORY_CODE, TBT.CARGO_CATEGORY_NAME, TBT.TRADE_TYPE, TBT.PLAN_QUANTITY, TBT.PLAN_TON, TBT.REMARK, TBT.SHIPVOYAGE_ID, TBT.SHIP_NAME, TBT.SETTLEMENT_BASIS_CODE, TBT.SETTLEMENT_BASIS_NAME, TBT.CHECK_TON, TBT.CHECK_NUMBER, TBT.COMPANY_ID, TBT.COMPANY_NAME, TBT.STATUS, TBT.CREATE_BY, TBT.CREATE_BY_NAME, TBT.CREATE_TIME, TBT.UPDATE_BY, TBT.UPDATE_BY_NAME, TBT.UPDATE_TIME, TBT.RELEASE_BY, TBT.RELEASE_BY_NAME, TBT.RELEASE_TIME, TBT.CHECK_BY, TBT.CHECK_BY_NAME, TBT.CHECK_TIME, TBT.EXAMINE_BY, TBT.EXAMINE_BY_NAME, TBT.EXAMINE_TIME, TBT.CARGO_OWNER_NAME, TBT.CARGO_AGENT_NAME, TBT.CARGO_NAME, TBT.SHIPVOYAGE_ITEM_ID, TBT.IMP_EXP, TBT.WORK_ACCOMPANYING_ID, TBT.IS_BILL, TBT.EST_AMOUNT, TBT.TYPE, TBT.START_TIME, TBT.END_TIME, TBT.POUND_REMARK, TBT.VOYAGE, TBT.PORT_CODE, TBT.PORT_NAME, TBT.IS_WEIQIAO_POUND_REMARK, TBT.PHH, TBT.CDH, TBT.IS_TOS, TBT.BZDM, TBT.BZMC, TBT.JHKSSJ, TBT.JHJSSJ, TBT.SOURCE, TBT.IS_REJECT, TBT.REJECT_BY, TBT.REJECT_BY_NAME, TBT.REJECT_REASON, TBT.REJECT_DATE, MAX(MC.NM) "statusLabel", (SELECT REGEXP_REPLACE( LISTAGG(TO_CHAR(TBTC.CARGO_OWNER_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_OWNER_NAME ), '([^,]+)(,\1)+', '\1') FROM TBTC WHERE TBT.ID = TBTC.TRUST_ID) "cargoOwnerName", (SELECT REGEXP_REPLACE( LISTAGG(TO_CHAR(TBTC.CARGO_AGENT_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_AGENT_NAME ), '([^,]+)(,\1)+', '\1') FROM TBTC WHERE TBT.ID = TBTC.TRUST_ID) "cargoAgentName", (SELECT REGEXP_REPLACE(LISTAGG(TO_CHAR(TBTC.CARGO_NAME), ',') WITHIN GROUP ( ORDER BY TBTC.CARGO_NAME ), '([^,]+)(,\1)+', '\1') FROM TBTC WHERE TBT.ID = TBTC.TRUST_ID) "cargoName", (SELECT REGEXP_REPLACE(LISTAGG(TO_CHAR( TBTC.CONSIGNER_ID), ',') WITHIN GROUP ( ORDER BY TBTC.CONSIGNER_ID), '([^,]+)(,\1)+', '\1') FROM TBTC WHERE TBT.ID = TBTC.TRUST_ID) CONSIGNER_ID,
(SELECT LISTAGG("shipNameVoyage", ',') WITHIN GROUP ( ORDER BY "shipNameVoyage" ) FROM TEMP WHERE TBT.ID = TEMP.ID) "shipNameVoyage", (SELECT LISTAGG(SCN, ',') WITHIN GROUP ( ORDER BY SCN ) FROM TEMP WHERE TBT.ID = TEMP.ID) "scn" FROM T_BUS_TRUST TBT JOIN M_CONSTANTS MC ON (MC.TYPE_CD = 'BUS_TRUST_STATUS' AND TBT.STATUS = MC.CD) LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBT.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN TBTC ON TBT.ID = TBTC.TRUST_ID LEFT JOIN TEMP ON TBT.ID = TEMP.ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID
TO_DATE(TO_CHAR(TBT.CREATE_TIME, 'YYYY-MM-DD'), 'YYYY-MM-DD') >= #{beginDate,jdbcType=TIMESTAMP}
AND TO_DATE(TO_CHAR(TBT.CREATE_TIME, 'YYYY-MM-DD'), 'YYYY-MM-DD') <= #{endDate,jdbcType=TIMESTAMP}
AND (CONSIGNER_ID IS NULL OR CONSIGNER_ID ='' )
AND (CONSIGNER_ID IS NOT NULL OR CONSIGNER_ID !='')
and TBT.TRUST_NO like #{trustNo}
and TBT.COMPANY_ID = #{companyId}
AND TEMP.SHIPVOYAGE_ITEM_ID IN #{shipvoyageItemId}
and TBTC.CARGO_OWNER_ID = #{cargoOwnerId,jdbcType=BIGINT}
and TBTC.BUSINESS_NO LIKE #{businessNoLike}
and TBT.STATUS = #{status}
and TBT.TRUST_TYPE = #{trustType, jdbcType=VARCHAR}
and TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}
and TBCI.CONTRACT_CODE LIKE #{contractCodeLike, jdbcType=VARCHAR}
and TBTC.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}
GROUP BY TBT.ID, TBT.TRUST_NO, TBT.TRUST_TYPE, TBT.CONTRACT_ID, TBT.CUSTOMER_ID, TBT.CUSTOMER_NAME, TBT.PROCESS_CODE,TBT.IS_REJECT, TBT.REJECT_BY, TBT.REJECT_BY_NAME, TBT.REJECT_REASON,TBT.REJECT_DATE,TBT.SOURCE, TBT.PROCESS_NAME, TBT.CARGO_CATEGORY_CODE, TBT.CARGO_CATEGORY_NAME, TBT.TRADE_TYPE, TBT.PLAN_QUANTITY, TBT.PLAN_TON, TBT.REMARK, TBT.SHIPVOYAGE_ID, TBT.SHIP_NAME, TBT.SETTLEMENT_BASIS_CODE, TBT.SETTLEMENT_BASIS_NAME, TBT.CHECK_TON, TBT.CHECK_NUMBER, TBT.COMPANY_ID, TBT.COMPANY_NAME, TBT.STATUS, TBT.CREATE_BY, TBT.CREATE_BY_NAME, TBT.CREATE_TIME, TBT.UPDATE_BY, TBT.UPDATE_BY_NAME, TBT.UPDATE_TIME, TBT.RELEASE_BY, TBT.RELEASE_BY_NAME, TBT.RELEASE_TIME, TBT.CHECK_BY, TBT.CHECK_BY_NAME, TBT.CHECK_TIME, TBT.EXAMINE_BY, TBT.EXAMINE_BY_NAME, TBT.EXAMINE_TIME, TBT.CARGO_OWNER_NAME, TBT.CARGO_AGENT_NAME, TBT.CARGO_NAME, TBT.SHIPVOYAGE_ITEM_ID, TBT.IMP_EXP, TBT.WORK_ACCOMPANYING_ID, TBT.IS_BILL, TBT.EST_AMOUNT, TBT.TYPE, TBT.START_TIME, TBT.END_TIME, TBT.POUND_REMARK, TBT.VOYAGE, TBT.PORT_CODE, TBT.PORT_NAME, TBT.IS_WEIQIAO_POUND_REMARK, TBT.PHH, TBT.CDH, TBT.IS_TOS, TBT.BZDM, TBT.BZMC, TBT.JHKSSJ, TBT.JHJSSJ ORDER BY TBT.CREATE_TIME DESC)

SELECT * FROM( SELECT M1.ID, M1.TRUST_NO, M1.TRUST_TYPE, M1.CONTRACT_ID, M1.CUSTOMER_ID, M1.CUSTOMER_NAME, M1.PROCESS_CODE, M1.PROCESS_NAME, M1.CARGO_CATEGORY_CODE, M1.CARGO_CATEGORY_NAME, M1.TRADE_TYPE, M1.PLAN_QUANTITY, M1.PLAN_TON, T3.CARGO_OWNER_NAME, T4.CARGO_AGENT_NAME, T5.CARGO_NAME, T5.CARGO_CODE, M1. REMARK, M1.SHIPVOYAGE_ID, M1.SHIPVOYAGE_ITEM_ID, CASE when TDS.ID IS NOT NULL then TDS.SHIP_NAME ||'_'|| T2.VOYAGE END "shipNameVoyage", M1.SETTLEMENT_BASIS_CODE, M1.SETTLEMENT_BASIS_NAME, M1.CHECK_TON, M1.CHECK_NUMBER, M1.COMPANY_ID, M1.COMPANY_NAME, M1.STATUS, M2.NM AS STATUS_LABEL, M1.CREATE_BY, M1.CREATE_BY_NAME, M1.CREATE_TIME, M1.UPDATE_BY, M1.UPDATE_BY_NAME, M1.UPDATE_TIME, M1.RELEASE_BY, M1.RELEASE_BY_NAME, M1.RELEASE_TIME, M1.CHECK_BY, M1.CHECK_BY_NAME, M1.CHECK_TIME, M1.EXAMINE_BY, M1.EXAMINE_BY_NAME, M1.EXAMINE_TIME, M1.IMP_EXP, M1.IS_BILL, M1.TYPE, M1.START_TIME, M1.END_TIME, M1.POUND_REMARK, CASE WHEN (SELECT COUNT(*) FROM T_BUS_TRUST_LOCATION T1 WHERE T1.TRUST_ID = M1.ID ) >0 THEN '已审核' ELSE '未审核' END AS "statusLabel" FROM T_BUS_TRUST M1 left join M_CONSTANTS M2 ON M1.STATUS = M2.CD and M2.TYPE_CD='BUS_TRUST_STATUS' LEFT JOIN (SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_NAME ),'([^,]+)(,\1)+', '\1' ) CARGO_OWNER_NAME,TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_OWNER_ID ), ',' ) WITHIN GROUP ( ORDER BY CARGO_OWNER_ID ), '([^,]+)(,\1)+', '\1' ) CARGO_OWNER_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T3 ON M1.ID = T3.TRUST_ID LEFT JOIN (SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_AGENT_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_AGENT_NAME ),'([^,]+)(,\1)+', '\1' ) CARGO_AGENT_NAME,TRUST_ID FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID ) T4 ON M1.ID = T4.TRUST_ID LEFT JOIN (SELECT REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_NAME ), ',' ) WITHIN GROUP ( ORDER BY CARGO_NAME ), '([^,]+)(,\1)+','\1' ) CARGO_NAME, TRUST_ID , REGEXP_REPLACE( LISTAGG ( TO_CHAR( CARGO_CODE ), ',' ) WITHIN GROUP ( ORDER BY CARGO_CODE ), '([^,]+)(,\1)+', '\1' ) CARGO_CODE FROM T_BUS_TRUST_CARGO GROUP BY TRUST_ID) T5 ON M1.ID = T5.TRUST_ID left join T_DIS_SHIPVOYAGE_ITEM T2 ON M1.SHIPVOYAGE_ITEM_ID = T2.ID left join T_DIS_SHIPVOYAGE TDS on t2.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON M1.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID
M1.TYPE IN ('集港','拆箱集港','疏港','陆销') and M1.STATUS IN ('30','40')
and M1.TRUST_NO like #{trustNo}
and M1.COMPANY_ID = #{companyId}
and CHARINDEX(#{customerId},M1.CUSTOMER_ID)
and ( M1.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId} OR TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId} )
and INSTR(T3.CARGO_OWNER_ID,#{cargoOwnerId})>0
AND INSTR(T5.CARGO_CODE,#{cargoCode})>0
and M1.STATUS = #{status}
) GROUP BY ID, TRUST_NO, TRUST_TYPE, CONTRACT_ID, CUSTOMER_ID, CUSTOMER_NAME, PROCESS_CODE, PROCESS_NAME, CARGO_CATEGORY_CODE, CARGO_CATEGORY_NAME, TRADE_TYPE, PLAN_QUANTITY, PLAN_TON, CARGO_OWNER_NAME, CARGO_AGENT_NAME, CARGO_NAME, CARGO_CODE, REMARK, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SETTLEMENT_BASIS_CODE, SETTLEMENT_BASIS_NAME, CHECK_TON, CHECK_NUMBER, COMPANY_ID, COMPANY_NAME, STATUS, STATUS_LABEL, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, RELEASE_BY, RELEASE_BY_NAME, RELEASE_TIME, CHECK_BY, CHECK_BY_NAME, CHECK_TIME, EXAMINE_BY, EXAMINE_BY_NAME, EXAMINE_TIME, IMP_EXP, IS_BILL, TYPE, START_TIME, END_TIME, "statusLabel", POUND_REMARK, "shipNameVoyage"
having "statusLabel" = '已审核'
having "statusLabel" = '未审核'
ORDER BY DECODE( "statusLabel", '已审核', 1, '未审核', 2, 3 ) DESC,CREATE_TIME DESC

mapper.update:
UPDATE
T_BUS_TRUST
SET
PLAN_QUANTITY = #{planQuantity,jdbcType=BIGINT},
PLAN_TON = #{planTon,jdbcType=DECIMAL}

    id = #{id}

mapper.select:
select sum(b.ton) as portStorageTon,sum(b.quantity) as portStorageQuantity,a.ID as CARGO_INFO_ID,a.TRADE_TYPE,a.CARGO_NAME, a.CARGO_CODE,a.SHIP_NAME,a.CARGO_OWNER_ID,a.CARGO_OWNER_NAME,a.SCN,a.CONTRACT_CODE, a.CARGO_AGENT_ID,a.CARGO_AGENT_NAME,a.PACKING_CODE,a.PACKING_NAME,c.WORK_TYPE,a.CARGO_INFO_NO, a.QUANTITY, a.TON, a.DELIVERY_ID,a.DELIVERY_NUMBERS,a.hatch_nums, TBTC.BUSINESS_NO,a.IS_PRE_PAY,a.IS_RELEASE,a.RELEASE_REMARK, CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN a.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE a.SHIP_NAME || '_' || TDSI.VOYAGE END) END "shipNameVoyage", CASE WHEN a.IS_TOS IS NOT NULL THEN a.IS_TOS ELSE TBT.TYPE END "type" from T_BUS_CARGO_INFO a LEFT JOIN T_PRD_PORT_STORAGE b on b.CARGO_INFO_ID=a.id and b.CLEAN_MASS_SIGN=0 inner join M_CARGO c on a.CARGO_CODE=c.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON a.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN T_BUS_TRUST TBT ON a.TRUST_ID = TBT.ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON (a.ID = TBTC.CARGO_INFO_ID AND TBT.ID = TBTC.TRUST_ID) LEFT JOIN (SELECT TBTC2.ID, TBTC2.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, CASE WHEN TBT2.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE TBT2.SHIP_NAME || '_' || TDSI2.VOYAGE END "shipNameVoyage" FROM T_BUS_TRUST_CARGO TBTC2 JOIN T_BUS_TRUST TBT2 ON TBTC2.TRUST_ID = TBT2.ID AND TBT2.TYPE = '装船' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI2 ON TBT2.SHIPVOYAGE_ITEM_ID = TDSI2.ID GROUP BY TBTC2.ID, TBTC2.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, TBT2.SHIP_NAME, TDSI2.VOYAGE ) TEMP ON a.ID = TEMP.CARGO_INFO_ID where (a.IS_CLEAR != 1 or a.IS_CLEAR is null) and a.IS_LOGOUT != 10 and a.COMPANY_ID=#{companyId}
AND A.TRADE_TYPE = #{tradeType,jdbcType=VARCHAR}
and a.CARGO_AGENT_ID=#{cargoAgentId}
and a.CARGO_OWNER_ID=#{cargoOwnerId}
AND CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TEMP.SHIPVOYAGE_ITEM_ID ELSE a.SHIPVOYAGE_ITEM_ID END = #{shipvoyageItemId}
and a.trust_id is not null
and a.SCN like #{scnLike}
and (TBT.TYPE IN ('集港', '拆箱集港') or a.TRUST_ID = '0' or a.SOURCE = '50')
and (TBT.TYPE NOT IN ('集港', '拆箱集港') or a.source = '20' or a.TRUST_ID = '0' or a.SOURCE = '50' or (a.SOURCE = '10' and a.trust_id is not null ) )
and a.CARGO_INFO_NO LIKE #{cargoInfoNoLike,jdbcType=VARCHAR}
AND TBTC.BUSINESS_NO LIKE #{businessNoLike,jdbcType=VARCHAR}
and a.SOURCE = #{trustType}
and a.trust_id is null
group by a.ID,a.TRADE_TYPE,a.CARGO_NAME, a.CARGO_CODE,a.SHIP_NAME,a.CARGO_OWNER_ID, a.CARGO_OWNER_NAME,a.CARGO_AGENT_ID, a.CARGO_AGENT_NAME,a.PACKING_CODE,a.PACKING_NAME,c.WORK_TYPE,a.CARGO_INFO_NO,a.SHIPVOYAGE_ITEM_ID, a.SHIP_NAME,TDSI.VOYAGE, a.QUANTITY, a.TON,a.IS_PRE_PAY,a.IS_RELEASE,a.RELEASE_REMARK, a.DELIVERY_ID,a.DELIVERY_NUMBERS,a.hatch_nums, a.SCN, a.CONTRACT_CODE, TBTC.BUSINESS_NO, TBT.TYPE, a.IS_TOS, a.CREATE_TIME order by DECODE(TBT.TYPE, '集港', 1, '卸船', 2), a.CREATE_TIME DESC

mapper.update:
UPDATE
    T_BUS_TRUST
SET STATUS = #{status,jdbcType=VARCHAR}
WHERE ID = #{id,jdbcType=VARCHAR}

mapper.select:
SELECT ID
FROM T_BUS_TRUST
WHERE WORK_ACCOMPANYING_ID = #{workAccompanyingId,jdbcType=BIGINT}
  AND ID != #{currentId,jdbcType=BIGINT}

SELECT M . ID AS ID, N.BUSINESS_NO AS planNo, G .SHIP_NAME AS vesselNameEn, G .SHIP_NAME AS vesselNameCn, G .VOYAGE AS voyageImport, 'SG/JG' AS billType, NVL (K .BHT_ID, E .BHT_ID) AS companyCode, CARGO.BHT_ID AS cargoCode, N.CARGO_NAME AS cargoName, B.planYard, '*' AS specs, N.PACKING_CODE AS packing, N.QUANTITY AS planQuantity, '0' AS finishQuantity, '0' AS surplusQuantity, N.TON AS planWeight, NVL(TEMP_T.WEIGHT_GOODS,'0') AS finishWeight, '0' AS surplusWeight, M .START_TIME AS planStartTime, M .END_TIME AS planEndTime, '0' AS orderQuantity, '0' AS isWeigh, '0' AS truckStop, '0' AS truckInPort, M.RELEASE_TIME FROM T_BUS_TRUST M LEFT JOIN T_BUS_TRUST_CARGO N ON M . ID = N.TRUST_ID LEFT JOIN M_WORK_PROCESS A ON M .PROCESS_CODE = A .PROCESS_CD LEFT JOIN ( SELECT TRUST_ID, REGEXP_REPLACE ( LISTAGG (TO_CHAR(planYard), ',') WITHIN GROUP (ORDER BY planYard), '([^,]+)(,\1)+', '\1' ) planYard FROM ( SELECT t1.BHT_ID || '/' || t2.STORAGE_YARD_NM AS planYard, REGION_ID, STOREHOUSE_ID, T .TRUST_ID FROM T_BUS_TRUST_LOCATION T LEFT JOIN M_STORAGE_YARD t1 ON T .STOREHOUSE_ID = t1. ID LEFT JOIN M_STORAGE_YARD t2 ON T .REGION_ID = t2. ID ) GROUP BY TRUST_ID ) B ON M . ID = B.TRUST_ID LEFT JOIN T_BUS_CUSTOMER E ON N.CARGO_OWNER_ID = E . ID LEFT JOIN T_BUS_CUSTOMER K ON N.CONSIGNER_ID = K . ID LEFT JOIN M_CARGO CARGO ON N.CARGO_CODE = CARGO.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON F. ID = M .SHIPVOYAGE_ITEM_ID LEFT JOIN T_BUS_CARGO_INFO G ON G . ID = N.CARGO_INFO_ID LEFT JOIN ( SELECT PLAN_NO, SUM (WEIGHT_GOODS) WEIGHT_GOODS FROM V_WEIGHT_INFO GROUP BY PLAN_NO ) TEMP_T ON TEMP_T.PLAN_NO = N.BUSINESS_NO
B.planYard IS NOT NULL AND M.END_TIME >= TO_DATE(TO_CHAR( SYSDATE, 'YYYY-MM-DD HH24:MI:SS' ), 'YYYY-MM-DD HH24:MI:SS')
AND NVL(K.BHT_ID, E.BHT_ID) = #{companyCode}
AND N.BUSINESS_NO = #{planNo}
AND CARGO.BHT_ID = #{cargoCode}
AND M.TYPE IN ('集港', '拆箱集港')
AND M.TYPE in ('疏港','陆销')
order by RELEASE_TIME DESC nulls last

