FROM t_truckplan
WHERE planCode = #{planCode}
  AND truckNumber = #{truckNumber}
  AND driverIDNumber = #{driverIDNumber}

mapper.update:
UPDATE T_BUS_TRUST
SET PLAN_QUANTITY = #{planQuantity,jdbcType=INTEGER},
    PLAN_TON      = #{planTon,jdbcType=DECIMAL}
WHERE WORK_ACCOMPANYING_ID = #{workAccompanyingId,jdbcType=BIGINT}

BEGIN
UPDATE T_BUS_TRUST_CARGO SET DELIVERY_NUMBERS = #{trustCargo.deliveryNumbers,jdbcType=VARCHAR}, QUANTITY = #{trustCargo.quantity,jdbcType=INTEGER}, TON = #{trustCargo.ton,jdbcType=DECIMAL}, IS_SECOND_WEIGH = #{trustCargo.isSecondWeigh,jdbcType=VARCHAR}, PRINT_POUND_ID = #{trustCargo.printPoundId,jdbcType=INTEGER}, EST_AMOUNT = #{trustCargo.estAmount,jdbcType=DECIMAL}, PRINT_POUND_NUM = #{trustCargo.printPoundNum,jdbcType=INTEGER}, STATUS = #{trustCargo._status,jdbcType=VARCHAR} WHERE ID = #{trustCargo.id,jdbcType=BIGINT};
END;

mapper.select:
SELECT TBTC.TRUST_ID "trustId", TDSI.ID "id", TDS.SHIP_NAME || '_' || TDSI.VOYAGE "shipNameVoyage", TBCI.SHIPVOYAGE_ITEM_ID "shipvoyageItemId" FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID JOIN T_DIS_SHIPVOYAGE TDS on TBCI.SHIPVOYAGE_ID = TDS.ID JOIN T_DIS_SHIPVOYAGE_ITEM TDSI on TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID WHERE EXISTS ( select * from (
select #{trustId, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TBTC.TRUST_ID ) GROUP BY TBTC.TRUST_ID, TDSI.ID, TDS.SHIP_NAME, TDSI.VOYAGE, TBCI.SHIPVOYAGE_ITEM_ID

SELECT TBTC.TRUST_ID "trustId", TDSI.ID "id", TDS.SHIP_NAME || '_' || TDSI.VOYAGE "shipNameVoyage", TBCI.SHIPVOYAGE_ITEM_ID "shipvoyageItemId" FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID JOIN T_DIS_SHIPVOYAGE TDS on TBCI.SHIPVOYAGE_ID = TDS.ID JOIN T_DIS_SHIPVOYAGE_ITEM TDSI on TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID WHERE EXISTS ( select * from (
select #{trustId, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TBTC.TRUST_ID ) GROUP BY TBTC.TRUST_ID, TDSI.ID, TDS.SHIP_NAME, TDSI.VOYAGE, TBCI.SHIPVOYAGE_ITEM_ID

mapper.update:
UPDATE
T_BUS_TRUST
SET
PORT_CODE = #{portCode,jdbcType=BIGINT},
PORT_NAME = #{portName, jdbcType=VARCHAR}

    id = #{id}

UPDATE
    t_tradeplan
SET planAmount = #{planAmount}
WHERE planCode = #{planCode}

UPDATE T_DIS_SHIPVOYAGE_ITEM
SET PRE_CHANGE_SHIP_NAME = #{preChangeShipName,jdbcType=VARCHAR},
    PRE_CHANGE_SHIP_NO   = #{preChangeShipNo,jdbcType=VARCHAR}
WHERE ID = #{id,jdbcType=BIGINT}

UPDATE T_BUS_TRUST_CARGO
SET IS_STOP = #{isStop,jdbcType=VARCHAR},
IS_STOP_OPERATION_BY = #{loginUserId, jdbcType=BIGINT},
IS_STOP_OPERATION_NAME = #{loginUserName, jdbcType=VARCHAR},
IS_STOP_OPERATION_TIME = #{now, jdbcType=TIMESTAMP}
WHERE ID = #{id,jdbcType=BIGINT}

mapper.select:
SELECT max(TBT.ID) AS id, count(TBT.ID) AS "idCount", SUM( DECODE( TBCI.IS_CLEAR,'1',1,'0',0,0) ) AS "clearNumber" FROM T_BUS_TRUST TBT LEFT JOIN T_BUS_TRUST_CARGO TBTC ON TBT.ID = TBTC.TRUST_ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBTC.CARGO_INFO_ID = TBCI.ID WHERE TBT.ID IN
#{item, jdbcType=BIGINT}
GROUP BY TBT.ID

SELECT COUNT(ID)
FROM T_BUS_VEHICLE_RESERVATION
WHERE DEL_FLAG = '0' AND TRUST_ID = #{id,jdbcType=BIGINT}

SELECT B.ID ID, C.BUSINESS_NO AS "planNo", D.SHIP_NAME AS "vesselNameEn", D.SHIP_NAME AS "vesselNameCn", D.VOYAGE AS "voyageImport", 'SG/JG' AS "billType", E.BHT_ID AS "companyCode", F.BHT_ID AS "cargoCode", F.CARGO_NAME AS "cargoName", G.planYard AS "planYard", '*' AS "specs", C.PACKING_CODE AS "packing", C.QUANTITY AS "planQuantity", '0' AS "finishQuantity", '0' AS "surplusQuantity", C.TON AS "planWeight", NVL(H.WEIGHT_GOODS,'0') AS "finishWeight", '0' AS surplusWeight, B.START_TIME AS "planStartTime", B.END_TIME AS "planEndTime", '0' AS "orderQuantity", '0' AS "isWeigh", '0' AS "truckStop", '0' AS "truckInPort", B.RELEASE_TIME FROM T_DIS_PORT_DAYNIGHTPLAN A LEFT JOIN T_BUS_TRUST B ON A.TRUST_ID = B.ID LEFT JOIN T_BUS_TRUST_CARGO C ON A.TRUST_CARGO_ID = C.ID LEFT JOIN T_BUS_CARGO_INFO D ON D.ID = C.CARGO_INFO_ID LEFT JOIN T_BUS_CUSTOMER E ON E.ID = A.CARGO_OWNER_ID LEFT JOIN M_CARGO F ON F.CARGO_CODE = A.CARGO_CODE LEFT JOIN (SELECT TRUST_ID,REGEXP_REPLACE (LISTAGG (TO_CHAR(planYard), ',') WITHIN GROUP (ORDER BY planYard),'([^,]+)(,\1)+','\1') planYard FROM ( SELECT t1.BHT_ID || '/' || t2.STORAGE_YARD_NM AS planYard, REGION_ID, STOREHOUSE_ID, T.TRUST_ID FROM T_BUS_TRUST_LOCATION T LEFT JOIN M_STORAGE_YARD t1 ON T .STOREHOUSE_ID = t1. ID LEFT JOIN M_STORAGE_YARD t2 ON T .REGION_ID = t2. ID ) GROUP BY TRUST_ID ) G ON G.TRUST_ID = A.TRUST_ID LEFT JOIN ( SELECT PLAN_NO, SUM (WEIGHT_GOODS) WEIGHT_GOODS FROM V_WEIGHT_INFO GROUP BY PLAN_NO ) H ON H.PLAN_NO = C.BUSINESS_NO
TO_CHAR( A.PLAN_DATE, 'yyyy-mm-dd' ) = CASE WHEN TO_CHAR( SYSDATE, 'HH24:MI' ) <= '18:00' THEN TO_CHAR( SYSDATE - 1, 'YYYY-MM-DD' ) ELSE TO_CHAR(SYSDATE, 'YYYY-MM-DD' ) END AND G.planYard IS NOT NULL
AND E.BHT_ID = #{companyCode}
AND C.BUSINESS_NO = #{planNo}
AND F.BHT_ID = #{cargoCode}
AND B.TYPE IN ('集港', '拆箱集港')
AND B.TYPE in ('疏港','陆销')

SELECT M . ID AS ID, N.BUSINESS_NO AS "planNo", ENTRUST.SUB_PLAN_NO AS "subPlanNo", G .SHIP_NAME AS "vesselNameEn", G .SHIP_NAME AS "vesselNameCn", G .VOYAGE AS "voyageImport", 'SG/JG' AS "billType", NVL (K .BHT_ID, E .BHT_ID) AS COMPANY_CODE, NVL (K .CUSTOMER_NAME, E .CUSTOMER_NAME) AS COMPANY_NAME, CARGO.BHT_ID AS "cargoCode", N.CARGO_NAME AS "cargoName", B.planYard, B.nameYard "nameYard", '*' AS "specs", N.PACKING_CODE AS "packing", N.QUANTITY AS "planQuantity", '0' AS "finishQuantity", '0' AS "surplusQuantity", N.TON AS planWeight, NVL(TEMP_T.WEIGHT_GOODS,'0') AS finishWeight, '0' AS surplusWeight, M .START_TIME AS planStartTime, M .END_TIME AS planEndTime, '0' AS orderQuantity, '0' AS isWeigh, '0' AS truckStop, '0' AS truckInPort, M.RELEASE_TIME, ENTRUST.CONSIGNEE_NAME, ENTRUST.CONSIGNEE_CODE, ENTRUST.QUANTITY ENTRUST_QUANTITY, ENTRUST.WEIGHT ENTRUST_WEIGHT FROM T_BUS_TRUST M LEFT JOIN T_BUS_TRUST_CARGO N ON M . ID = N.TRUST_ID LEFT JOIN M_WORK_PROCESS A ON M .PROCESS_CODE = A .PROCESS_CD LEFT JOIN ( SELECT TRUST_ID, REGEXP_REPLACE ( LISTAGG (TO_CHAR(planYard), ',') WITHIN GROUP (ORDER BY planYard), '([^,]+)(,\1)+', '\1' ) planYard, REGEXP_REPLACE ( LISTAGG (TO_CHAR(nameYard), ',') WITHIN GROUP (ORDER BY nameYard), '([^,]+)(,\1)+', '\1' ) nameYard FROM ( SELECT t1.BHT_ID || '/' || t2.STORAGE_YARD_NM AS planYard, t1.STORAGE_YARD_NM || '/' || t2.STORAGE_YARD_NM AS nameYard, REGION_ID, STOREHOUSE_ID, T .TRUST_ID FROM T_BUS_TRUST_LOCATION T LEFT JOIN M_STORAGE_YARD t1 ON T .STOREHOUSE_ID = t1. ID LEFT JOIN M_STORAGE_YARD t2 ON T .REGION_ID = t2. ID ) GROUP BY TRUST_ID ) B ON M . ID = B.TRUST_ID LEFT JOIN T_BUS_CUSTOMER E ON N.CARGO_OWNER_ID = E . ID LEFT JOIN T_BUS_CUSTOMER K ON N.CONSIGNER_ID = K . ID LEFT JOIN M_CARGO CARGO ON N.CARGO_CODE = CARGO.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON F. ID = M .SHIPVOYAGE_ITEM_ID LEFT JOIN T_BUS_CARGO_INFO G ON G . ID = N.CARGO_INFO_ID LEFT JOIN ( SELECT PLAN_NO, SUM (WEIGHT_GOODS) WEIGHT_GOODS FROM V_WEIGHT_INFO GROUP BY PLAN_NO ) TEMP_T ON TEMP_T.PLAN_NO = N.BUSINESS_NO LEFT JOIN T_BUS_PLAN_ENTRUST ENTRUST ON ENTRUST.PLAN_NO = N.BUSINESS_NO
B.planYard IS NOT NULL
AND NVL(K.BHT_ID, E.BHT_ID) = #{companyCode}
AND N.BUSINESS_NO = #{planNo}
AND CARGO.BHT_ID = #{cargoCode}
AND M.TYPE IN ('集港', '拆箱集港')
AND M.TYPE in ('疏港','陆销')
order by RELEASE_TIME DESC nulls last

SELECT B.ID ID, C.BUSINESS_NO AS "planNo", L.SUB_PLAN_NO AS "subPlanNo", D.SHIP_NAME AS "vesselNameEn", D.SHIP_NAME AS "vesselNameCn", D.VOYAGE AS "voyageImport", 'SG/JG' AS "billType", E.BHT_ID AS "companyCode", F.BHT_ID AS "cargoCode", F.CARGO_NAME AS "cargoName", G.planYard AS "planYard", '*' AS "specs", C.PACKING_CODE AS "packing", C.QUANTITY AS "planQuantity", '0' AS "finishQuantity", '0' AS "surplusQuantity", C.TON AS "planWeight", NVL(H.WEIGHT_GOODS,'0') AS "finishWeight", '0' AS surplusWeight, A.BEGIN_TIME AS "planStartTime", A.END_TIME AS "planEndTime", '0' AS "orderQuantity", '0' AS "isWeigh", '0' AS "truckStop", '0' AS "truckInPort", A.PLAN_DATE RELEASE_TIME FROM T_DIS_PORT_DAYNIGHTPLAN A LEFT JOIN T_BUS_TRUST B ON A.TRUST_ID = B.ID LEFT JOIN T_BUS_TRUST_CARGO C ON A.TRUST_CARGO_ID = C.ID LEFT JOIN T_BUS_CARGO_INFO D ON D.ID = C.CARGO_INFO_ID LEFT JOIN T_BUS_CUSTOMER E ON E.ID = A.CARGO_OWNER_ID LEFT JOIN M_CARGO F ON F.CARGO_CODE = A.CARGO_CODE LEFT JOIN (SELECT TRUST_ID,REGEXP_REPLACE (LISTAGG (TO_CHAR(planYard), ',') WITHIN GROUP (ORDER BY planYard),'([^,]+)(,\1)+','\1') planYard FROM ( SELECT t1.BHT_ID || '/' || t2.STORAGE_YARD_NM AS planYard, REGION_ID, STOREHOUSE_ID, T.TRUST_ID FROM T_BUS_TRUST_LOCATION T LEFT JOIN M_STORAGE_YARD t1 ON T .STOREHOUSE_ID = t1. ID LEFT JOIN M_STORAGE_YARD t2 ON T .REGION_ID = t2. ID ) GROUP BY TRUST_ID ) G ON G.TRUST_ID = A.TRUST_ID LEFT JOIN ( SELECT PLAN_NO, SUM (WEIGHT_GOODS) WEIGHT_GOODS FROM V_WEIGHT_INFO GROUP BY PLAN_NO ) H ON H.PLAN_NO = C.BUSINESS_NO LEFT JOIN T_BUS_PLAN_ENTRUST L ON L.PLAN_NO = C.BUSINESS_NO
TO_CHAR( A.PLAN_DATE, 'yyyy-mm-dd' ) = CASE WHEN TO_CHAR( SYSDATE, 'HH24:MI' ) <= '18:00' THEN TO_CHAR( SYSDATE - 1, 'YYYY-MM-DD' ) ELSE TO_CHAR(SYSDATE, 'YYYY-MM-DD' ) END AND G.planYard IS NOT NULL
AND E.BHT_ID = #{companyCode}
AND C.BUSINESS_NO = #{planNo}
AND F.BHT_ID = #{cargoCode}
AND B.TYPE IN ('集港', '拆箱集港')
AND B.TYPE in ('疏港','陆销')
order by RELEASE_TIME DESC nulls last

SELECT M.ID AS ID, N.BUSINESS_NO AS planNo, G.SHIP_NAME AS vesselNameEn, G.SHIP_NAME AS vesselNameCn, G.VOYAGE AS voyageImport, 'SG/JG' AS billType, NVL( K.BHT_ID, E.BHT_ID ) AS companyCode, CARGO.BHT_ID AS cargoCode, N.CARGO_NAME AS cargoName, B.planYard, '*' AS specs, N.PACKING_CODE AS packing, NVL( DAYNIGHT.PLAN_TON, 0 ) AS planQuantity, '0' AS finishQuantity, '0' AS surplusQuantity, NVL( DAYNIGHT.PLAN_TON, 0 ) AS planWeight, NVL( TEMP_T.WEIGHT_GOODS, '0' ) AS finishWeight, '0' AS surplusWeight, DAYNIGHT.BEGIN_TIME AS planStartTime, DAYNIGHT.END_TIME AS planEndTime, DAYNIGHT.PLAN_DATE, '0' AS orderQuantity, '0' AS isWeigh, '0' AS truckStop, '0' AS truckInPort, M.RELEASE_TIME FROM T_BUS_TRUST M LEFT JOIN T_BUS_TRUST_CARGO N ON M.ID = N.TRUST_ID LEFT JOIN M_WORK_PROCESS A ON M.PROCESS_CODE = A.PROCESS_CD LEFT JOIN ( SELECT TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( planYard ), ',' ) WITHIN GROUP ( ORDER BY planYard ), '([^,]+)(,\1)+', '\1' ) planYard FROM ( SELECT t1.BHT_ID || '/' || t2.STORAGE_YARD_NM AS planYard, REGION_ID, STOREHOUSE_ID, T.TRUST_ID FROM T_BUS_TRUST_LOCATION T LEFT JOIN M_STORAGE_YARD t1 ON T.STOREHOUSE_ID = t1.ID LEFT JOIN M_STORAGE_YARD t2 ON T.REGION_ID = t2.ID ) GROUP BY TRUST_ID ) B ON M.ID = B.TRUST_ID LEFT JOIN T_BUS_CUSTOMER E ON N.CARGO_OWNER_ID = E.ID LEFT JOIN T_BUS_CUSTOMER K ON N.CONSIGNER_ID = K.ID LEFT JOIN M_CARGO CARGO ON N.CARGO_CODE = CARGO.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON F.ID = M.SHIPVOYAGE_ITEM_ID LEFT JOIN T_BUS_CARGO_INFO G ON G.ID = N.CARGO_INFO_ID LEFT JOIN ( SELECT PLAN_NO, SUM( WEIGHT_GOODS ) WEIGHT_GOODS FROM V_WEIGHT_INFO GROUP BY PLAN_NO ) TEMP_T ON TEMP_T.PLAN_NO = N.BUSINESS_NO LEFT JOIN ( SELECT MAX( BUSINESS_NO ) BUSINESS_NO, SUM( PLAN_TON ) PLAN_TON, MIN( BEGIN_TIME ) BEGIN_TIME, MAX( END_TIME ) END_TIME, PLAN_DATE FROM T_DIS_PORT_DAYNIGHTPLAN GROUP BY PLAN_DATE ) DAYNIGHT ON N.BUSINESS_NO = DAYNIGHT.BUSINESS_NO
TO_CHAR( DAYNIGHT.PLAN_DATE, 'yyyy-mm-dd' ) = CASE WHEN TO_CHAR( SYSDATE, 'HH24:MI' ) <= '18:00' THEN TO_CHAR( SYSDATE - 1, 'YYYY-MM-DD' ) ELSE TO_CHAR(SYSDATE, 'YYYY-MM-DD' ) END AND DAYNIGHT.BUSINESS_NO IS NOT NULL AND B.planYard IS NOT NULL
AND NVL(K.BHT_ID, E.BHT_ID) = #{companyCode}
AND N.BUSINESS_NO = #{planNo}
AND CARGO.BHT_ID = #{cargoCode}
AND M.TYPE IN ('集港', '拆箱集港')
AND M.TYPE in ('疏港','陆销')
order by RELEASE_TIME DESC nulls last

SELECT M.ID AS ID, N.BUSINESS_NO AS planNo, G.SHIP_NAME AS vesselNameEn, G.SHIP_NAME AS vesselNameCn, G.VOYAGE AS voyageImport, 'SG/JG' AS billType, NVL( K.BHT_ID, E.BHT_ID ) AS companyCode, CARGO.BHT_ID AS cargoCode, N.CARGO_NAME AS cargoName, B.planYard, '*' AS specs, N.PACKING_CODE AS packing, NVL(DAYNIGHT.PLAN_TON,0) AS planQuantity, '0' AS finishQuantity, '0' AS surplusQuantity, NVL(DAYNIGHT.PLAN_TON,0) AS planWeight, NVL( TEMP_T.WEIGHT_GOODS, '0' ) AS finishWeight, '0' AS surplusWeight, DAYNIGHT.BEGIN_TIME AS planStartTime, DAYNIGHT.END_TIME AS planEndTime, '0' AS orderQuantity, '0' AS isWeigh, '0' AS truckStop, '0' AS truckInPort, M.RELEASE_TIME FROM T_BUS_TRUST M LEFT JOIN T_BUS_TRUST_CARGO N ON M.ID = N.TRUST_ID LEFT JOIN M_WORK_PROCESS A ON M.PROCESS_CODE = A.PROCESS_CD LEFT JOIN ( SELECT TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( planYard ), ',' ) WITHIN GROUP ( ORDER BY planYard ), '([^,]+)(,\1)+', '\1' ) planYard FROM ( SELECT t1.BHT_ID || '/' || t2.STORAGE_YARD_NM AS planYard, REGION_ID, STOREHOUSE_ID, T.TRUST_ID FROM T_BUS_TRUST_LOCATION T LEFT JOIN M_STORAGE_YARD t1 ON T.STOREHOUSE_ID = t1.ID LEFT JOIN M_STORAGE_YARD t2 ON T.REGION_ID = t2.ID ) GROUP BY TRUST_ID ) B ON M.ID = B.TRUST_ID LEFT JOIN T_BUS_CUSTOMER E ON N.CARGO_OWNER_ID = E.ID LEFT JOIN T_BUS_CUSTOMER K ON N.CONSIGNER_ID = K.ID LEFT JOIN M_CARGO CARGO ON N.CARGO_CODE = CARGO.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON F.ID = M.SHIPVOYAGE_ITEM_ID LEFT JOIN T_BUS_CARGO_INFO G ON G.ID = N.CARGO_INFO_ID LEFT JOIN ( SELECT PLAN_NO, SUM( WEIGHT_GOODS ) WEIGHT_GOODS FROM V_WEIGHT_INFO GROUP BY PLAN_NO ) TEMP_T ON TEMP_T.PLAN_NO = N.BUSINESS_NO LEFT JOIN T_DIS_PORT_DAYNIGHTPLAN DAYNIGHT ON N.BUSINESS_NO = DAYNIGHT.BUSINESS_NO
TO_CHAR( DAYNIGHT.PLAN_DATE, 'yyyy-mm-dd' ) = CASE WHEN TO_CHAR( SYSDATE, 'HH24:MI' ) <= '18:00' THEN TO_CHAR( SYSDATE - 1, 'YYYY-MM-DD' ) ELSE TO_CHAR(SYSDATE, 'YYYY-MM-DD' ) END AND TO_CHAR(BEGIN_TIME,'YYYY-MM-DD HH24:MI:SS') <= TO_CHAR(SYSDATE,'YYYY-MM-DD HH24:MI:SS') AND TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS' ) <= TO_CHAR(END_TIME,'YYYY-MM-DD HH24:MI:SS') AND DAYNIGHT.BUSINESS_NO IS NOT NULL AND B.planYard IS NOT NULL
AND NVL(K.BHT_ID, E.BHT_ID) = #{companyCode}
AND N.BUSINESS_NO = #{planNo}
AND CARGO.BHT_ID = #{cargoCode}
AND M.TYPE IN ('集港', '拆箱集港')
AND M.TYPE in ('疏港','陆销')
order by RELEASE_TIME DESC nulls last

