SELECT M.ID AS ID, N.BUSINESS_NO AS "planNo", ENTRUST.SUB_PLAN_NO AS "subPlanNo", G.SHIP_NAME AS vesselNameEn, G.SHIP_NAME AS vesselNameCn, G.VOYAGE AS voyageImport, 'SG/JG' AS billType, NVL (K .BHT_ID, E .BHT_ID) AS "companyCode", NVL (K .CUSTOMER_NAME, E .CUSTOMER_NAME) AS "companyName", CARGO.BHT_ID AS "cargoCode", N.CARGO_NAME AS "cargoName", B.planYard, B.nameYard "nameYard", '*' AS specs, N.PACKING_CODE AS packing, NVL(DAYNIGHT.PLAN_TON,0) AS planQuantity, '0' AS finishQuantity, '0' AS surplusQuantity, NVL(DAYNIGHT.PLAN_TON,0) AS planWeight, NVL( TEMP_T.WEIGHT_GOODS, '0' ) AS finishWeight, '0' AS surplusWeight, DAYNIGHT.BEGIN_TIME AS planStartTime, DAYNIGHT.END_TIME AS planEndTime, '0' AS orderQuantity, '0' AS isWeigh, '0' AS truckStop, '0' AS truckInPort, M.RELEASE_TIME, ENTRUST.CONSIGNEE_NAME, ENTRUST.CONSIGNEE_CODE, ENTRUST.QUANTITY ENTRUST_QUANTITY, ENTRUST.WEIGHT ENTRUST_WEIGHT FROM T_BUS_TRUST M LEFT JOIN T_BUS_TRUST_CARGO N ON M.ID = N.TRUST_ID LEFT JOIN M_WORK_PROCESS A ON M.PROCESS_CODE = A.PROCESS_CD LEFT JOIN ( SELECT TRUST_ID, REGEXP_REPLACE( LISTAGG ( TO_CHAR( planYard ), ',' ) WITHIN GROUP ( ORDER BY planYard ), '([^,]+)(,\1)+', '\1' ) planYard, REGEXP_REPLACE( LISTAGG (TO_CHAR(nameYard), ',') WITHIN GROUP (ORDER BY nameYard),'([^,]+)(,\1)+','\1') nameYard FROM ( SELECT t1.BHT_ID || '/' || t2.STORAGE_YARD_NM AS planYard, t1.STORAGE_YARD_NM || '/' || t2.STORAGE_YARD_NM AS nameYard, REGION_ID, STOREHOUSE_ID, T.TRUST_ID FROM T_BUS_TRUST_LOCATION T LEFT JOIN M_STORAGE_YARD t1 ON T.STOREHOUSE_ID = t1.ID LEFT JOIN M_STORAGE_YARD t2 ON T.REGION_ID = t2.ID ) GROUP BY TRUST_ID ) B ON M.ID = B.TRUST_ID LEFT JOIN T_BUS_CUSTOMER E ON N.CARGO_OWNER_ID = E.ID LEFT JOIN T_BUS_CUSTOMER K ON N.CONSIGNER_ID = K.ID LEFT JOIN M_CARGO CARGO ON N.CARGO_CODE = CARGO.CARGO_CODE LEFT JOIN T_DIS_SHIPVOYAGE_ITEM F ON F.ID = M.SHIPVOYAGE_ITEM_ID LEFT JOIN T_BUS_CARGO_INFO G ON G.ID = N.CARGO_INFO_ID LEFT JOIN ( SELECT PLAN_NO, SUM( WEIGHT_GOODS ) WEIGHT_GOODS FROM V_WEIGHT_INFO GROUP BY PLAN_NO ) TEMP_T ON TEMP_T.PLAN_NO = N.BUSINESS_NO LEFT JOIN T_DIS_PORT_DAYNIGHTPLAN DAYNIGHT ON M.ID = DAYNIGHT.TRUST_ID LEFT JOIN T_BUS_PLAN_ENTRUST ENTRUST ON ENTRUST.PLAN_NO = N.BUSINESS_NO
TO_CHAR( DAYNIGHT.PLAN_DATE, 'yyyy-mm-dd' ) = CASE WHEN TO_CHAR( SYSDATE, 'HH24:MI' ) <= '18:00' THEN TO_CHAR( SYSDATE - 1, 'YYYY-MM-DD' ) ELSE TO_CHAR(SYSDATE, 'YYYY-MM-DD' ) END AND B.planYard IS NOT NULL
AND NVL(K.BHT_ID, E.BHT_ID) = #{companyCode}
AND N.BUSINESS_NO = #{planNo}
AND CARGO.BHT_ID = #{cargoCode}
AND M.TYPE IN ('集港', '拆箱集港')
AND M.TYPE in ('疏港','陆销')
order by RELEASE_TIME DESC nulls last

SELECT ID,IS_CLEAR,CARGO_INFO_NO,IS_LOGOUT
FROM T_BUS_CARGO_INFO
WHERE ID = #{cargoInfoId}

select ID
from T_DIS_PORT_DAYNIGHTPLAN where EXISTS (
select * from (

    select #{trustCargoId, jdbcType=BIGINT} as TMPID
    from dual

) a where a.TMPID =  TRUST_CARGO_ID
)

select TBTC.id "TBTCID", TBTC.CARGO_INFO_ID "cargoInfoId", TBC.PAY_TYPE "payType" from T_BUS_TRUST_CARGO TBTC left join T_BUS_TRUST TBT on TBT.id = TBTC.TRUST_ID left join T_BUS_CONTRACT TBC on TBTC.CONTRACT_ID = TBC.ID where TBT.TYPE in ('集港','卸船') and exists( select * from (
select #{tmp_id, jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TBTC.CARGO_INFO_ID )

SELECT TBO.SHIP_NAME, TBO.VOYAGE , TBO.SHIP_NAME || '_' || tbo.VOYAGE "shipNameVoyage", TBO.SHIPVOYAGE_ID "shipvoyageId", TBO.SHIPVOYAGE_ITEM_ID "shipvoyageItemId", tboi.ID "orderItemId", tboi.BILL_NO "billNo", TBCI.ID cargo_Info_Id, TBCI.CARGO_INFO_NO "cargoInfoNo", tbci.CARGO_OWNER_ID "cargoOwnerId", TBCI.CARGO_OWNER_NAME "cargoOwnerName", TBCI.CARGO_NAME, TBCI.CARGO_CODE "cargoCode", TBCI.PACKING_CODE "packingCode", TBCI.PACKING_NAME "packingName", TBOI.QUANTITY "quantity", TBOI.TON "ton", SUM(tpps.QUANTITY) portStorageQuantity, SUM(tpps.TON) portStorageTon, TBCI.TRADE_TYPE , mc.WORK_TYPE , tbci.HATCH_NUMS , CASE WHEN tbci.IS_TOS IS NOT NULL THEN tbci.IS_TOS ELSE TBT.TYPE END "type", tbci.IS_PRE_PAY, tbci.IS_RELEASE, tbci.RELEASE_REMARK, tbci.CONTRACT_CODE, tbci.CARGO_AGENT_ID, tbci.CARGO_AGENT_NAME FROM T_BUS_ORDER_ITEM tboi LEFT JOIN T_BUS_ORDER tbo ON tbo.id = tboi.order_id LEFT JOIN T_BUS_CARGO_INFO tbci ON tbci.ID = TBOI.CARGO_INFO_ID LEFT JOIN T_PRD_PORT_STORAGE tpps ON TPPS.CARGO_INFO_ID = TBCI.ID LEFT JOIN M_CARGO mc ON mc.CARGO_CODE = TBCI.CARGO_CODE LEFT JOIN T_BUS_TRUST_CARGO tbtc ON TBTC.CARGO_INFO_ID = TBOI.CARGO_INFO_ID LEFT JOIN T_BUS_TRUST tbt ON tbt.ID = tbci.TRUST_ID
tbo.STATUS = 1
AND TBCI.CARGO_INFO_NO = #{cargoInfoNo}
AND tbo.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
AND tboi.BILL_NO = #{billNo}
AND tboi.BILL_NO = #{billNo}
AND TBCI.CARGO_INFO_NO = #{cargoInfoNo}
GROUP BY TBO.SHIP_NAME, tbo.VOYAGE, TBO.SHIPVOYAGE_ID , TBO.SHIPVOYAGE_ITEM_ID , tboi.ID, tboi.BILL_NO , TBCI.ID , TBCI.CARGO_INFO_NO , tbci.CARGO_OWNER_ID , TBCI.CARGO_OWNER_NAME , TBCI.CARGO_NAME , TBCI.CARGO_CODE , TBCI.PACKING_CODE , TBCI.PACKING_NAME , TBOI.QUANTITY , TBOI.TON, TBCI.TRADE_TYPE , tbci.HATCH_NUMS , mc.WORK_TYPE, TBT.TYPE, tbci.IS_TOS, tbci.IS_PRE_PAY, tbci.IS_RELEASE, tbci.RELEASE_REMARK, tbci.CONTRACT_CODE, tbci.CARGO_AGENT_ID, tbci.CARGO_AGENT_NAME

select *
from T_BUS_TRUST_STOP_LOG


        and TRUST_CARGO_ID = #{trustCargoId}


        and id = #{id}


